namespace sv_880de0283a2b4a28a0f3239327651958.Models;

public class ApplicationData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> ExperienceEntries { get; set; } = new();
    public List<ReferenceContact> References { get; set; } = new();
    public HashSet<int> CompletedSteps { get; set; } = new();
}

public class PersonalInfo
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class ExperienceEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Duration { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_880de0283a2b4a28a0f3239327651958.Models;

namespace sv_880de0283a2b4a28a0f3239327651958.Services;

/// <summary>
/// Singleton service that stores wizard data keyed by ASP.NET session ID.
/// This bridges the static-SSR layout and interactive-server pages, which
/// live in different DI scopes but share the same session cookie.
/// </summary>
public class ApplicationStateService
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new ApplicationData());
    }
}

