using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Http;
using sv_880de0283a2b4a28a0f3239327651958.Models;
using sv_880de0283a2b4a28a0f3239327651958.Services;

namespace sv_880de0283a2b4a28a0f3239327651958.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles the static → interactive
/// boundary by caching the session ID via PersistentComponentState
/// (available during prerender, persisted into the interactive circuit).
/// </summary>
public abstract class WizardStepBase : ComponentBase
{
    [Inject] public required ApplicationStateService StateService { get; set; }
    [Inject] public required NavigationManager Nav { get; set; }
    [Inject] public required PersistentComponentState PersistentState { get; set; }

    [CascadingParameter] public HttpContext? HttpContext { get; set; }

    protected string SessionId { get; private set; } = string.Empty;
    protected ApplicationData Data { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        if (HttpContext is not null)
        {
            // Prerender: HttpContext is available — grab the session ID and
            // register it for persistence so the interactive circuit can use it.
            SessionId = HttpContext.Session.Id;
            _subscription = PersistentState.RegisterOnPersisting(() =>
            {
                PersistentState.PersistAsJson("wizardSessionId", SessionId);
                return Task.CompletedTask;
            });
        }
        else
        {
            // Interactive mode: retrieve the session ID persisted during prerender.
            if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var id) && id is not null)
            {
                SessionId = id;
            }
        }

        Data = StateService.GetOrCreate(SessionId);
    }

    protected void MarkStepComplete(int step, string nextUrl)
    {
        Data.CompletedSteps.Add(step);
        Nav.NavigateTo(nextUrl);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

@inherits LayoutComponentBase
@layout MainLayout
@inject NavigationManager Nav
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_880de0283a2b4a28a0f3239327651958.Services.ApplicationStateService StateService

@{
    var steps = new (string Url, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review"),
    };

    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    int currentStep = 0;
    for (int i = 0; i < steps.Length; i++)
    {
        if (currentPath.Equals(steps[i].Url, StringComparison.OrdinalIgnoreCase))
        {
            currentStep = i + 1;
            break;
        }
    }

    var sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? string.Empty;
    var data = StateService.GetOrCreate(sessionId);
}

<div class="wizard-progress mb-4">
    <p class="fw-bold mb-2">Step @currentStep of @steps.Length</p>
    <div class="d-flex gap-2 mb-3">
        @for (int i = 0; i < steps.Length; i++)
        {
            var step = steps[i];
            var stepNum = i + 1;
            var isActive = stepNum == currentStep;
            var isComplete = data.CompletedSteps.Contains(stepNum);
            var css = isActive ? "btn-primary" : isComplete ? "btn-success" : "btn-outline-secondary";

            <a href="@step.Url" class="btn btn-sm @css">
                @stepNum. @step.Label
                @if (isComplete) { <span>✓</span> }
            </a>
        }
    </div>
    <div class="progress" style="height: 6px;">
        <div class="progress-bar" role="progressbar"
             style="width: @(currentStep * 100 / steps.Length)%">
        </div>
    </div>
</div>

@Body

