@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Apply — Review</PageTitle>

<h3>Step 4: Review Your Application</h3>

<div class="card mb-3">
    <div class="card-header fw-bold">Personal Information</div>
    <div class="card-body">
        <p><strong>Name:</strong> @Data.PersonalInfo.Name</p>
        <p><strong>Email:</strong> @Data.PersonalInfo.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header fw-bold">Work Experience</div>
    <div class="card-body">
        @if (Data.ExperienceEntries.Count == 0)
        {
            <p class="text-muted">No entries added.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Company</th><th>Title</th><th>Duration</th></tr></thead>
                <tbody>
                    @foreach (var e in Data.ExperienceEntries)
                    {
                        <tr><td>@e.Company</td><td>@e.Title</td><td>@e.Duration</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header fw-bold">References</div>
    <div class="card-body">
        @if (Data.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
                <tbody>
                    @foreach (var r in Data.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <a href="/apply/references" class="btn btn-outline-secondary">← Back</a>
    <button class="btn btn-success" @onclick="OnSubmit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private bool _submitted;

    private void OnSubmit()
    {
        Data.CompletedSteps.Add(4);
        _submitted = true;
    }
}

