@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Apply — Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="Data.PersonalInfo" OnValidSubmit="OnNext" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Data.PersonalInfo.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="Data.PersonalInfo.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private void OnNext() => MarkStepComplete(1, "/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits WizardStepBase

<PageTitle>Apply — Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@if (Data.ExperienceEntries.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Duration</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var entry in Data.ExperienceEntries)
            {
                <tr>
                    <td>@entry.Company</td>
                    <td>@entry.Title</td>
                    <td>@entry.Duration</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(entry)">✕</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<h5>Add Entry</h5>
<EditForm Model="_newEntry" OnValidSubmit="AddEntry" FormName="experience-entry">
    <div class="row g-2 mb-3">
        <div class="col">
            <InputText class="form-control" placeholder="Company" @bind-Value="_newEntry.Company" />
        </div>
        <div class="col">
            <InputText class="form-control" placeholder="Job Title" @bind-Value="_newEntry.Title" />
        </div>
        <div class="col">
            <InputText class="form-control" placeholder="Duration (e.g. 2 years)" @bind-Value="_newEntry.Duration" />
        </div>
        <div class="col-auto">
            <button type="submit" class="btn btn-outline-primary">Add</button>
        </div>
    </div>
</EditForm>

<div class="d-flex justify-content-between">
    <a href="/apply/personal-info" class="btn btn-outline-secondary">← Back</a>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    private ExperienceEntry _newEntry = new();

    private void AddEntry()
    {
        Data.ExperienceEntries.Add(_newEntry);
        _newEntry = new();
    }

    private void Remove(ExperienceEntry entry) => Data.ExperienceEntries.Remove(entry);

    private void OnNext() => MarkStepComplete(2, "/apply/references");
}

